import { Component, inject, signal, computed, OnInit } from '@angular/core';

import { FormsModule } from '@angular/forms';
import { debounceTime, Subject } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { TrackingStore } from '@kaufmann/tracking-otd/data-access';
import { VinModel, EstadoVin, LineaNegocio, HITO_LABELS, HITOS_IDS } from '@kaufmann/shared/models';
import { StatusBadgeComponent } from '@kaufmann/shared/ui';
import { VehicleIconComponent } from '@kaufmann/shared/ui';
import { TrackingDrawerComponent } from '../../components/tracking-drawer/tracking-drawer.component';
import { formatDate } from '@kaufmann/shared/utils';

@Component({
    selector: 'kf-tracking-list-page',
    imports: [FormsModule, StatusBadgeComponent, VehicleIconComponent, TrackingDrawerComponent],
    templateUrl: './tracking-list-page.component.html'
})
export class TrackingListPageComponent implements OnInit {
  readonly store = inject(TrackingStore);

  readonly HITO_LABELS = HITO_LABELS;
  readonly HITO_IDS = [...HITOS_IDS];

  currentPage = signal(1);
  readonly pageSize = 20;

  searchInput$ = new Subject<string>();
  searchValue = signal('');

  estadoOptions: EstadoVin[] = ['A TIEMPO', 'DEMORADO', 'FINALIZADO'];
  lineaOptions: LineaNegocio[] = ['VC', 'Autos', 'Maquinarias', 'Buses'];
  empresaOptions = ['Divemotor', 'Andes Motor', 'Andes Maq'];

  pagedVins = computed(() => {
    const all = this.store.vinsFiltrados();
    const start = (this.currentPage() - 1) * this.pageSize;
    return all.slice(start, start + this.pageSize);
  });

  totalPages = computed(() => Math.max(1, Math.ceil(this.store.vinsFiltrados().length / this.pageSize)));

  constructor() {
    this.searchInput$.pipe(
      debounceTime(300),
      takeUntilDestroyed()
    ).subscribe(val => {
      this.store.setFiltro('busqueda', val);
      this.currentPage.set(1);
    });
  }

  ngOnInit() {}

  onSearch(value: string) {
    this.searchValue.set(value);
    this.searchInput$.next(value);
  }

  setEstado(e: Event) {
    const val = (e.target as HTMLSelectElement).value as EstadoVin | '';
    this.store.setFiltro('estado', val || null);
    this.currentPage.set(1);
  }

  setLinea(e: Event) {
    const val = (e.target as HTMLSelectElement).value as LineaNegocio | '';
    this.store.setFiltro('lineaNegocio', val || null);
    this.currentPage.set(1);
  }

  setEmpresa(e: Event) {
    const val = (e.target as HTMLSelectElement).value;
    this.store.setFiltro('empresa', val || null);
    this.currentPage.set(1);
  }

  openDrawer(vinId: string, stageId?: string) {
    this.store.openDrawer(vinId, stageId);
  }

  getHitoStatus(vin: VinModel, hitoId: string): string {
    return vin.stages.find(s => s.id === hitoId)?.status ?? 'pending';
  }

  getHitoDotClass(status: string): string {
    switch (status) {
      case 'completed': return 'bg-emerald-500';
      case 'delayed':   return 'bg-red-500 animate-pulse';
      case 'active':    return 'bg-blue-500 animate-pulse';
      default:          return 'bg-slate-200';
    }
  }

  formatDate = formatDate;

  prevPage() { if (this.currentPage() > 1) this.currentPage.update(p => p - 1); }
  nextPage() { if (this.currentPage() < this.totalPages()) this.currentPage.update(p => p + 1); }

  lineaBadge(linea: string): string {
    switch (linea) {
      case 'VC':
      case 'Camiones': return 'bg-blue-100 text-blue-700 border border-blue-200';
      case 'Autos':    return 'bg-purple-100 text-purple-700 border border-purple-200';
      case 'Maquinarias': return 'bg-orange-100 text-orange-700 border border-orange-200';
      case 'Buses':    return 'bg-sky-100 text-sky-700 border border-sky-200';
      default:         return 'bg-slate-100 text-slate-600 border border-slate-200';
    }
  }

  pagoPill(forma: string): string {
    switch (forma) {
      case 'Leasing':              return 'bg-violet-100 text-violet-700';
      case 'Renting':              return 'bg-pink-100 text-pink-700';
      case 'Contado':              return 'bg-emerald-100 text-emerald-700';
      case 'Financiamiento directo':
      case 'Financiamiento BK':   return 'bg-amber-100 text-amber-700';
      default:                    return 'bg-slate-100 text-slate-600';
    }
  }
}
<div class="p-6 min-h-full">

  <!-- Header -->
  <div class="mb-6">
    <h1 class="text-xl font-bold text-slate-800">Tracking OTD</h1>
    <p class="text-sm text-slate-500 mt-0.5">
      {{ store.vinsFiltrados().length }} VINs encontrados ·
      <span class="text-red-600 font-medium">{{ store.totalDemorados() }} demorados</span>
    </p>
  </div>

  <!-- Filters bar -->
  <div class="bg-white rounded-lg border border-slate-200 shadow-sm p-4 mb-4 flex flex-wrap gap-3 items-center">
    <!-- Search -->
    <div class="relative flex-1 min-w-48">
      <input
        type="text"
        placeholder="Buscar VIN, cliente, ficha, modelo…"
        [value]="searchValue()"
        (input)="onSearch($any($event.target).value)"
        class="w-full pl-8 pr-3 py-2 text-sm rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder-slate-400"
        />
      <span class="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400 text-sm">🔍</span>
    </div>

    <!-- Empresa filter -->
    <select
      (change)="setEmpresa($event)"
      class="text-sm rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
      >
      <option value="">Todas las empresas</option>
      @for (e of empresaOptions; track e) {
        <option [value]="e">{{ e }}</option>
      }
    </select>

    <!-- Línea de negocio filter -->
    <select
      (change)="setLinea($event)"
      class="text-sm rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
      >
      <option value="">Todas las líneas</option>
      @for (l of lineaOptions; track l) {
        <option [value]="l">{{ l }}</option>
      }
    </select>

    <!-- View mode toggle -->
    <button
      (click)="store.toggleViewMode()"
      class="px-3 py-2 text-sm rounded-lg border border-slate-200 bg-slate-50 text-slate-600 hover:bg-slate-100 transition-colors"
      [attr.aria-label]="store.viewMode() === 'grouped' ? 'Cambiar a lista plana' : 'Agrupar por cliente'"
      >
      {{ store.viewMode() === 'grouped' ? '☰ Lista' : '🗂 Agrupado' }}
    </button>

    <!-- Estado filter -->
    <select
      (change)="setEstado($event)"
      class="text-sm rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
      >
      <option value="">Todos los estados</option>
      @for (s of estadoOptions; track s) {
        <option [value]="s">{{ s }}</option>
      }
    </select>

  </div>

  <!-- Table -->
  <div class="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
    <div class="overflow-x-auto">
      <table class="w-full text-sm">
        <thead>
          <tr class="bg-slate-50 border-b border-slate-200">
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap">Cliente</th>
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap">VIN / Modelo</th>
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap">Ficha</th>
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Lote</th>
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide">Estado</th>
            <!-- 9 Hito columns -->
            @for (hId of HITO_IDS; track hId) {
              <th
                class="px-2 py-3 text-center text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap"
                title="{{ HITO_LABELS[hId] }}">
                {{ HITO_LABELS[hId] }}
              </th>
            }
            <th class="text-center px-3 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap">Días</th>
            <th class="text-left px-4 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wide whitespace-nowrap">Actualiz.</th>
          </tr>
        </thead>
        <tbody>
          @if (pagedVins().length === 0) {
            <tr>
              <td [attr.colspan]="14 + HITO_IDS.length" class="text-center py-12 text-slate-400">
                No se encontraron VINs con los filtros actuales.
              </td>
            </tr>
          }
          @for (vin of pagedVins(); track vin) {
            <tr
              (click)="openDrawer(vin.id)"
              class="border-b border-slate-100 hover:bg-slate-50 transition-colors duration-100 cursor-pointer group"
              >
              <!-- Cliente -->
              <td class="px-4 py-3">
                <span class="font-medium text-slate-800 text-xs truncate max-w-32 block">{{ vin.clientName }}</span>
              </td>
              <!-- VIN / Modelo -->
              <td class="px-4 py-3">
                <div class="flex items-center gap-2">
                  <kf-vehicle-icon [lineaNegocio]="vin.lineaNegocio" size="sm" />
                  <div class="min-w-0">
                    <div class="font-mono text-xs text-slate-700 truncate max-w-36">{{ vin.id }}</div>
                    <div class="text-xs text-slate-500 truncate max-w-36">{{ vin.modelo }}</div>
                  </div>
                  <span class="text-xs px-1.5 py-0.5 rounded-full font-medium flex-shrink-0" [class]="lineaBadge(vin.lineaNegocio)">
                    {{ vin.lineaNegocio }}
                  </span>
                </div>
              </td>
              <!-- Ficha -->
              <td class="px-4 py-3">
                <div class="text-xs font-medium text-slate-700">{{ vin.fichaId }}</div>
              </td>
              <!-- Lote -->
              <td class="px-4 py-3">
                <span class="text-xs text-slate-600">{{ vin.lote }}</span>
              </td>
              <!-- Estado -->
              <td class="px-4 py-3">
                <kf-status-badge [status]="$any(vin.estadoGeneral)" />
              </td>
              <!-- Hito dots -->
              @for (hId of HITO_IDS; track hId) {
                <td
                  class="px-2 py-3 text-center"
                  (click)="$event.stopPropagation(); openDrawer(vin.id, hId)"
                  >
                  <span
                    class="inline-block w-3 h-3 rounded-full cursor-pointer hover:scale-125 transition-transform"
                    [class]="getHitoDotClass(getHitoStatus(vin, hId))"
                    [attr.title]="HITO_LABELS[hId] + ': ' + getHitoStatus(vin, hId)"
                  ></span>
                </td>
              }
              <!-- Días retraso -->
              <td class="px-3 py-3 text-center">
                <span
                  class="text-xs font-semibold"
                  [class]="vin.daysDelayed > 0 ? 'text-red-600' : 'text-emerald-600'"
                  >
                  {{ vin.daysDelayed > 0 ? '+' + vin.daysDelayed : vin.daysDelayed === 0 ? '0' : vin.daysDelayed }}
                </span>
              </td>
              <!-- Actualización -->
              <td class="px-4 py-3">
                <span class="text-xs text-slate-500">{{ vin.lastUpdate }}</span>
              </td>
            </tr>
          }
        </tbody>
      </table>
    </div>

    <!-- Pagination -->
    @if (totalPages() > 1) {
      <div class="flex items-center justify-between px-4 py-3 border-t border-slate-200 bg-slate-50">
        <span class="text-xs text-slate-500">
          Página {{ currentPage() }} de {{ totalPages() }} ·
          {{ store.vinsFiltrados().length }} resultados
        </span>
        <div class="flex gap-2">
          <button
            (click)="prevPage()"
            [disabled]="currentPage() === 1"
            class="px-3 py-1.5 text-xs rounded border border-slate-200 bg-white text-slate-600 disabled:opacity-40 hover:bg-slate-100 transition-colors"
          >← Anterior</button>
          <button
            (click)="nextPage()"
            [disabled]="currentPage() === totalPages()"
            class="px-3 py-1.5 text-xs rounded border border-slate-200 bg-white text-slate-600 disabled:opacity-40 hover:bg-slate-100 transition-colors"
          >Siguiente →</button>
        </div>
      </div>
    }
  </div>

</div>

<!-- Drawer overlay -->
@if (store.drawerOpen()) {
  <div
    class="fixed inset-0 bg-black/40 z-40 transition-opacity"
    (click)="store.closeDrawer()"
    aria-hidden="true"
  ></div>
}

<!-- Tracking Drawer -->
@if (store.selectedVin()) {
  <kf-tracking-drawer
    [vin]="store.selectedVin()!"
    [selectedStageId]="store.selectedStageId()"
    [isOpen]="store.drawerOpen()"
    (closed)="store.closeDrawer()"
    />
}
